--------------------------------------------------------
--  DDL for View V_ADMIN_QUEUE
--------------------------------------------------------

  CREATE OR REPLACE FORCE EDITIONABLE VIEW "PRINTADMIN"."V_ADMIN_QUEUE" ("JOB_ID", "DESCRIPTION", "PAGE_COUNT", "JOB_TYPE", "PRINT_SIDE", "COPIES", "TOTAL_COST", "SUBMISSION_TIME", "COLLECTION_SLOT", "EXPIRY_TIME", "PRIORITY_LEVEL", "STATUS_NAME", "FIRST_NAME", "LAST_NAME", "EMAIL") AS 
  SELECT 
    pj.Job_Id,
    pj.description,
    pj.Page_count,
    pj.job_type,
    pj.print_side,
    pj.copies,
    pj.total_cost,
    pj.Submission_Time,
    pj.collection_slot,
    pj.expiry_time,
    pj.Priority_level,
    js.Status_Name,
    au.first_name,
    au.last_name,
    au.EMail
FROM PRINT_JOB pj
JOIN SUBMITS s ON pj.Job_Id = s.Job_Id
JOIN APP_USER au ON s.User_ID = au.User_ID
JOIN HAS_STATUS hs ON pj.Job_Id = hs.Job_Id
JOIN JOB_STATUS js ON hs.Status_ID = js.Status_ID
WHERE js.Status_Name NOT IN ('Cancelled', 'Collected', 'Discarded')
ORDER BY pj.Priority_level DESC, pj.Submission_Time ASC
;
--------------------------------------------------------
--  DDL for View V_DAILY_REPORT
--------------------------------------------------------

  CREATE OR REPLACE FORCE EDITIONABLE VIEW "PRINTADMIN"."V_DAILY_REPORT" ("REPORT_DATE", "TOTAL_JOBS", "NORMAL_JOBS", "BULK_JOBS", "TOTAL_REVENUE", "TOTAL_PAGES") AS 
  SELECT 
    TRUNC(pj.Submission_Time) AS report_date,
    COUNT(pj.Job_Id) AS total_jobs,
    SUM(CASE WHEN pj.job_type = 'normal' THEN 1 ELSE 0 END) AS normal_jobs,
    SUM(CASE WHEN pj.job_type = 'bulk' THEN 1 ELSE 0 END) AS bulk_jobs,
    SUM(pj.total_cost) AS total_revenue,
    SUM(pj.Page_count) AS total_pages
FROM PRINT_JOB pj
WHERE pj.Submission_Time >= SYSDATE - 30
GROUP BY TRUNC(pj.Submission_Time)
ORDER BY report_date DESC
;
--------------------------------------------------------
--  DDL for View V_JOB_DETAILS
--------------------------------------------------------

  CREATE OR REPLACE FORCE EDITIONABLE VIEW "PRINTADMIN"."V_JOB_DETAILS" ("JOB_ID", "USER_ID", "DOCUMENT", "DESCRIPTION", "SUBMISSION_TIME", "COMPLETION_TIME", "PAGE_COUNT", "COPIES", "JOB_TYPE", "PRINT_MODE", "PRINT_SIDE", "PRICE_PER_PAGE", "TOTAL_COST", "QR_SECURE_TOKEN", "PRIORITY_LEVEL", "COLLECTION_SLOT", "EXPIRY_TIME", "STATUS_NAME", "KIOSK_ID", "BIN_ID") AS 
  SELECT 
    pj.JOB_ID,
    s.USER_ID,
    pj.DOCUMENT,
    pj.DESCRIPTION,
    pj.SUBMISSION_TIME,
    pj.COMPLETION_TIME,
    pj.PAGE_COUNT,
    pj.COPIES,
    pj.JOB_TYPE,
    pj.PRINT_MODE,
    pj.PRINT_SIDE,
    pj.PRICE_PER_PAGE,
    pj.TOTAL_COST,
    pj.QR_SECURE_TOKEN,
    pj.PRIORITY_LEVEL,
    pj.COLLECTION_SLOT,
    pj.EXPIRY_TIME,
    js.STATUS_NAME,
    pi.KIOSK_ID,
    pi.BIN_ID
FROM PRINT_JOB pj
JOIN SUBMITS s ON pj.JOB_ID = s.JOB_ID
JOIN HAS_STATUS hs ON pj.JOB_ID = hs.JOB_ID
JOIN JOB_STATUS js ON hs.STATUS_ID = js.STATUS_ID
LEFT JOIN PLACED_IN pi ON pj.JOB_ID = pi.JOB_ID
;
--------------------------------------------------------
--  DDL for View V_TRANSACTION_HISTORY
--------------------------------------------------------

  CREATE OR REPLACE FORCE EDITIONABLE VIEW "PRINTADMIN"."V_TRANSACTION_HISTORY" ("TRANSACTION_ID", "USER_ID", "AMOUNT", "TRANSACTION_DATE", "TRANSACTION_TYPE", "BALANCE_AFTER", "JOB_ID") AS 
  SELECT 
    ft.Transaction_ID,
    ft.User_ID,
    ft.Amount,
    ft.Transaction_date,
    ft.transaction_type,
    ft.balance_after,
    g.Job_Id
FROM FINANCIAL_TRANSACTION ft
LEFT JOIN GENERATES g ON ft.Transaction_ID = g.Transaction_ID
;
--------------------------------------------------------
--  DDL for View V_USER_PROFILE
--------------------------------------------------------

  CREATE OR REPLACE FORCE EDITIONABLE VIEW "PRINTADMIN"."V_USER_PROFILE" ("USER_ID", "FIRST_NAME", "LAST_NAME", "EMAIL", "PROFILE_PICTURE", "ACTIVE_SESSION", "LAST_LOGIN_TIMESTAMP", "ACCOUNT_BALANCE", "ROLE", "MAJOR", "STUDENT_BATCH", "DEPARTMENT", "FACULTY_RANK") AS 
  SELECT 
    au.User_ID,
    au.first_name,
    au.last_name,
    au.EMail,
    au.profile_picture,
    au.Active_session,
    au.last_login_timestamp,
    nu.Account_balance,
    CASE 
        WHEN a.User_ID IS NOT NULL THEN 'admin'
        WHEN o.User_ID IS NOT NULL THEN 'operator'
        WHEN f.User_ID IS NOT NULL THEN 'faculty'
        WHEN st.User_ID IS NOT NULL THEN 'student'
        ELSE 'unknown'
    END AS role,
    st.Major,
    st.Student_Batch,
    f.Department,
    f.Faculty_Rank
FROM APP_USER au
LEFT JOIN NORMAL_USER nu ON au.User_ID = nu.User_ID
LEFT JOIN ADMIN a ON au.User_ID = a.User_ID
LEFT JOIN OPERATOR o ON au.User_ID = o.User_ID
LEFT JOIN STUDENT st ON au.User_ID = st.User_ID
LEFT JOIN FACULTY f ON au.User_ID = f.User_ID
;
